import bisect

class SORTracker:

    def __init__(self):
        self.locations = []
        self.query_index = 0

    def add(self, name: str, score: int) -> None:
        bisect.insort(self.locations, (-score, name))

    def get(self) -> str:
        result = self.locations[self.query_index][1]
        self.query_index += 1
        return result
